import { useEffect, useState } from "react";
import { useAuth } from "../../context/AuthContext";
import { db } from "../../firebase/config";
import { collection, query, where, getDocs } from "firebase/firestore";
import { Calendar, Clock, CreditCard, Package } from "lucide-react";
import { Link } from "react-router-dom";

export const ClientDashboard = () => {
  const { currentUser, userProfile } = useAuth();
  const [stats, setStats] = useState({
    totalBookings: 0,
    pendingBookings: 0,
    confirmedBookings: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      if (!currentUser) return;
      
      try {
        const bookingsRef = collection(db, "bookings");
        const q = query(bookingsRef, where("userId", "==", currentUser.uid));
        const querySnapshot = await getDocs(q);
        
        let total = 0;
        let pending = 0;
        let confirmed = 0;

        querySnapshot.forEach((doc) => {
          total++;
          const data = doc.data();
          if (data.status === "pending") pending++;
          if (data.status === "confirmed") confirmed++;
        });

        setStats({
          totalBookings: total,
          pendingBookings: pending,
          confirmedBookings: confirmed,
        });
      } catch (error) {
        console.error("Error fetching dashboard stats:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchStats();
  }, [currentUser]);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <span className="animate-spin h-8 w-8 border-2 border-primary border-t-transparent rounded-full"></span>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-serif text-primary mb-2">
          Welcome back, {userProfile?.name || "Client"}
        </h1>
        <p className="text-secondary/70">Here is an overview of your account.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-dark-paper p-6 rounded-xl border border-primary/20 shadow-lg">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-secondary/70 text-sm font-medium mb-1">Total Bookings</p>
              <h3 className="text-3xl font-serif text-light">{stats.totalBookings}</h3>
            </div>
            <div className="bg-primary/10 p-3 rounded-lg">
              <Package className="w-6 h-6 text-primary" />
            </div>
          </div>
        </div>

        <div className="bg-dark-paper p-6 rounded-xl border border-primary/20 shadow-lg">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-secondary/70 text-sm font-medium mb-1">Pending Requests</p>
              <h3 className="text-3xl font-serif text-light">{stats.pendingBookings}</h3>
            </div>
            <div className="bg-primary/10 p-3 rounded-lg">
              <Clock className="w-6 h-6 text-primary" />
            </div>
          </div>
        </div>

        <div className="bg-dark-paper p-6 rounded-xl border border-primary/20 shadow-lg">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-secondary/70 text-sm font-medium mb-1">Confirmed Events</p>
              <h3 className="text-3xl font-serif text-light">{stats.confirmedBookings}</h3>
            </div>
            <div className="bg-primary/10 p-3 rounded-lg">
              <Calendar className="w-6 h-6 text-primary" />
            </div>
          </div>
        </div>

        <div className="bg-dark-paper p-6 rounded-xl border border-primary/20 shadow-lg">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-secondary/70 text-sm font-medium mb-1">Payment Status</p>
              <h3 className="text-xl font-serif text-light mt-2">Up to date</h3>
            </div>
            <div className="bg-primary/10 p-3 rounded-lg">
              <CreditCard className="w-6 h-6 text-primary" />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-dark-paper p-8 rounded-xl border border-primary/20 shadow-lg">
          <h2 className="text-xl font-serif text-primary mb-4">Quick Actions</h2>
          <div className="space-y-4">
            <Link
              to="/booking"
              className="block w-full text-center bg-primary text-dark font-medium py-3 rounded-lg hover:bg-primary/90 transition-colors"
            >
              Book New Event
            </Link>
            <Link
              to="/client/bookings"
              className="block w-full text-center bg-dark border border-primary/50 text-primary font-medium py-3 rounded-lg hover:bg-primary/10 transition-colors"
            >
              View All Bookings
            </Link>
          </div>
        </div>

        <div className="bg-dark-paper p-8 rounded-xl border border-primary/20 shadow-lg flex flex-col justify-center items-center text-center">
          <div className="bg-primary/10 p-4 rounded-full mb-4">
            <CreditCard className="w-8 h-8 text-primary" />
          </div>
          <h2 className="text-xl font-serif text-primary mb-2">Need to make a payment?</h2>
          <p className="text-secondary/70 mb-6 text-sm">
            Check your pending payments and invoices in the payments section.
          </p>
          <Link
            to="/client/payments"
            className="text-primary hover:text-primary/80 font-medium underline underline-offset-4"
          >
            Go to Payments
          </Link>
        </div>
      </div>
    </div>
  );
};
