import { useEffect, useState } from "react";
import { useAuth } from "../../context/AuthContext";
import { db } from "../../firebase/config";
import { collection, query, where, getDocs, orderBy } from "firebase/firestore";
import { Calendar, Clock, MapPin, Package, FileText, ChevronRight } from "lucide-react";
import { Link } from "react-router-dom";

interface BookingData {
  id: string;
  eventType: string;
  package: string;
  eventDate: string;
  time: string;
  location: string;
  status: string;
  notes?: string;
  createdAt: any;
}

export const ClientBookings = () => {
  const { currentUser } = useAuth();
  const [bookings, setBookings] = useState<BookingData[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      if (!currentUser) return;
      
      try {
        const bookingsRef = collection(db, "bookings");
        // Note: if you use orderBy with where on different fields, it might require a composite index in Firestore.
        // For simplicity and avoiding index requirement errors for now, we'll fetch and sort locally if needed,
        // or just rely on the query if no orderBy is used.
        const q = query(
          bookingsRef, 
          where("userId", "==", currentUser.uid)
        );
        const querySnapshot = await getDocs(q);
        
        const fetchedBookings: BookingData[] = [];
        querySnapshot.forEach((doc) => {
          fetchedBookings.push({ id: doc.id, ...doc.data() } as BookingData);
        });

        // Sort by eventDate descending locally to avoid missing index errors
        fetchedBookings.sort((a, b) => new Date(b.eventDate).getTime() - new Date(a.eventDate).getTime());

        setBookings(fetchedBookings);
      } catch (error) {
        console.error("Error fetching bookings:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, [currentUser]);

  const getStatusColor = (status: string) => {
    switch (status.toLowerCase()) {
      case "pending": return "text-yellow-500 bg-yellow-500/10 border-yellow-500/20";
      case "confirmed": return "text-green-500 bg-green-500/10 border-green-500/20";
      case "completed": return "text-blue-500 bg-blue-500/10 border-blue-500/20";
      case "cancelled": return "text-red-500 bg-red-500/10 border-red-500/20";
      default: return "text-secondary bg-secondary/10 border-secondary/20";
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <span className="animate-spin h-8 w-8 border-2 border-primary border-t-transparent rounded-full"></span>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-serif text-primary mb-2">My Bookings</h1>
          <p className="text-secondary/70">View and manage your event bookings.</p>
        </div>
        <Link
          to="/booking"
          className="bg-primary text-dark font-medium px-6 py-2 rounded-lg hover:bg-primary/90 transition-colors"
        >
          New Booking
        </Link>
      </div>

      {bookings.length === 0 ? (
        <div className="bg-dark-paper p-12 rounded-xl border border-primary/20 shadow-lg text-center">
          <Calendar className="w-16 h-16 text-primary/50 mx-auto mb-4" />
          <h2 className="text-xl font-serif text-light mb-2">No bookings found</h2>
          <p className="text-secondary/70 mb-6">You haven't made any event bookings yet.</p>
          <Link
            to="/booking"
            className="inline-block bg-primary text-dark font-medium px-8 py-3 rounded-lg hover:bg-primary/90 transition-colors"
          >
            Book Your First Event
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {bookings.map((booking) => (
            <div key={booking.id} className="bg-dark-paper p-6 rounded-xl border border-primary/20 shadow-lg hover:border-primary/40 transition-colors group">
              <div className="flex justify-between items-start mb-6">
                <div>
                  <h3 className="text-xl font-serif text-light capitalize mb-1">
                    {booking.eventType} Event
                  </h3>
                  <p className="text-secondary/70 text-sm flex items-center gap-1">
                    <Package className="w-4 h-4" />
                    <span className="capitalize">{booking.package} Package</span>
                  </p>
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-medium border uppercase tracking-wider ${getStatusColor(booking.status)}`}>
                  {booking.status}
                </span>
              </div>

              <div className="space-y-3 mb-6">
                <div className="flex items-center gap-3 text-light">
                  <div className="bg-dark p-2 rounded-lg border border-primary/10">
                    <Calendar className="w-4 h-4 text-primary" />
                  </div>
                  <span>{new Date(booking.eventDate).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                </div>
                
                <div className="flex items-center gap-3 text-light">
                  <div className="bg-dark p-2 rounded-lg border border-primary/10">
                    <Clock className="w-4 h-4 text-primary" />
                  </div>
                  <span>{booking.time}</span>
                </div>

                <div className="flex items-center gap-3 text-light">
                  <div className="bg-dark p-2 rounded-lg border border-primary/10">
                    <MapPin className="w-4 h-4 text-primary" />
                  </div>
                  <span className="truncate">{booking.location}</span>
                </div>
              </div>

              {booking.notes && (
                <div className="mb-6 bg-dark p-4 rounded-lg border border-primary/10">
                  <div className="flex items-center gap-2 text-secondary/70 mb-2 text-sm">
                    <FileText className="w-4 h-4" />
                    <span>Notes</span>
                  </div>
                  <p className="text-light text-sm line-clamp-2">{booking.notes}</p>
                </div>
              )}

              <div className="pt-4 border-t border-primary/10 flex justify-end">
                <button className="text-primary text-sm font-medium hover:text-primary/80 flex items-center gap-1 transition-colors">
                  View Details <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};
