import { Outlet, Link, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { Camera, LayoutDashboard, Calendar, Users, Package, CreditCard, Settings, LogOut, FileText } from "lucide-react";
import { auth } from "../firebase/config";

export const DashboardLayout = () => {
  const { userProfile } = useAuth();
  const location = useLocation();
  const isAdmin = userProfile?.role === "admin";

  const adminLinks = [
    { name: "Overview", path: "/admin/dashboard", icon: LayoutDashboard },
    { name: "Bookings", path: "/admin/bookings", icon: Calendar },
    { name: "Clients", path: "/admin/clients", icon: Users },
    { name: "Packages", path: "/admin/packages", icon: Package },
    { name: "Payments", path: "/admin/payments", icon: CreditCard },
    { name: "Reports", path: "/admin/reports", icon: FileText },
    { name: "Settings", path: "/admin/settings", icon: Settings },
  ];

  const clientLinks = [
    { name: "Overview", path: "/client/dashboard", icon: LayoutDashboard },
    { name: "My Bookings", path: "/client/bookings", icon: Calendar },
    { name: "Payments", path: "/client/payments", icon: CreditCard },
    { name: "Profile", path: "/client/profile", icon: Settings },
  ];

  const links = isAdmin ? adminLinks : clientLinks;

  const handleLogout = async () => {
    await auth.signOut();
  };

  return (
    <div className="flex h-screen bg-dark">
      {/* Sidebar */}
      <aside className="w-64 bg-dark-paper border-r border-gray-800 flex flex-col">
        <div className="h-20 flex items-center px-6 border-b border-gray-800">
          <Link to="/" className="flex items-center space-x-2">
            <Camera className="h-8 w-8 text-primary" />
            <span className="font-serif text-xl font-bold tracking-wider text-light">SnapBook</span>
          </Link>
        </div>
        
        <div className="flex-1 py-6 overflow-y-auto">
          <nav className="space-y-1 px-4">
            {links.map((link) => {
              const Icon = link.icon;
              const isActive = location.pathname === link.path;
              return (
                <Link
                  key={link.path}
                  to={link.path}
                  className={`flex items-center space-x-3 px-4 py-3 rounded-md transition-colors ${
                    isActive 
                      ? "bg-primary/10 text-primary" 
                      : "text-gray-400 hover:bg-gray-800 hover:text-light"
                  }`}
                >
                  <Icon className="h-5 w-5" />
                  <span className="font-medium">{link.name}</span>
                </Link>
              );
            })}
          </nav>
        </div>

        <div className="p-4 border-t border-gray-800">
          <div className="flex items-center space-x-3 px-4 py-3 mb-4">
            <div className="h-10 w-10 rounded-full bg-gray-800 flex items-center justify-center text-primary font-serif text-lg">
              {userProfile?.name?.charAt(0) || "U"}
            </div>
            <div>
              <p className="text-sm font-medium text-light truncate w-32">{userProfile?.name}</p>
              <p className="text-xs text-gray-500 capitalize">{userProfile?.role}</p>
            </div>
          </div>
          <button 
            onClick={handleLogout}
            className="flex w-full items-center space-x-3 px-4 py-3 text-red-400 hover:bg-red-400/10 rounded-md transition-colors"
          >
            <LogOut className="h-5 w-5" />
            <span className="font-medium">Logout</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-dark p-8">
        <Outlet />
      </main>
    </div>
  );
};