import { useState, useEffect } from "react";
import { useAuth } from "../../context/AuthContext";
import { db } from "../../firebase/config";
import { doc, setDoc } from "firebase/firestore";
import { User, Mail, Phone, MapPin, Camera } from "lucide-react";
import Swal from "sweetalert2";

export const ClientProfile = () => {
  const { currentUser, userProfile } = useAuth();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    address: "",
  });

  useEffect(() => {
    if (userProfile) {
      setFormData({
        name: userProfile.name || currentUser?.displayName || "",
        email: userProfile.email || currentUser?.email || "",
        phone: (userProfile as any).phone || "",
        address: (userProfile as any).address || "",
      });
    } else if (currentUser) {
      setFormData({
        name: currentUser.displayName || "",
        email: currentUser.email || "",
        phone: "",
        address: "",
      });
    }
  }, [userProfile, currentUser]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    setLoading(true);
    try {
      const userRef = doc(db, "users", currentUser.uid);
      await setDoc(userRef, {
        name: formData.name,
        email: formData.email,
        phone: formData.phone,
        address: formData.address,
        role: userProfile?.role || "client",
        updatedAt: new Date(),
      }, { merge: true });

      Swal.fire({
        icon: "success",
        title: "Profile Updated",
        text: "Your profile information has been saved successfully.",
        background: "#1E1E1E",
        color: "#F5F5DC",
        confirmButtonColor: "#D4AF37",
      });
    } catch (error: any) {
      console.error("Error updating profile:", error);
      Swal.fire({
        icon: "error",
        title: "Update Failed",
        text: error.message || "Could not update your profile. Please try again.",
        background: "#1E1E1E",
        color: "#F5F5DC",
        confirmButtonColor: "#D4AF37",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8 max-w-4xl">
      <div>
        <h1 className="text-3xl font-serif text-primary mb-2">My Profile</h1>
        <p className="text-secondary/70">Manage your personal information and contact details.</p>
      </div>

      <div className="bg-dark-paper rounded-xl border border-primary/20 shadow-lg overflow-hidden">
        <div className="p-8 border-b border-primary/20 flex flex-col md:flex-row items-center gap-6">
          <div className="relative group cursor-pointer">
            <div className="w-24 h-24 rounded-full bg-primary/10 border-2 border-primary/30 flex items-center justify-center overflow-hidden">
              {currentUser?.photoURL ? (
                <img src={currentUser.photoURL} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <User className="w-10 h-10 text-primary" />
              )}
            </div>
            <div className="absolute inset-0 bg-dark/60 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
              <Camera className="w-6 h-6 text-primary" />
            </div>
          </div>
          <div className="text-center md:text-left">
            <h2 className="text-2xl font-serif text-light mb-1">{formData.name || "Client Name"}</h2>
            <p className="text-secondary/70">{formData.email}</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-secondary flex items-center gap-2 text-sm font-medium">
                <User className="w-4 h-4 text-primary" />
                Full Name
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleChange}
                className="w-full bg-dark border border-primary/30 text-light rounded-lg px-4 py-3 focus:outline-none focus:border-primary transition-colors"
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-secondary flex items-center gap-2 text-sm font-medium">
                <Mail className="w-4 h-4 text-primary" />
                Email Address
              </label>
              <input
                type="email"
                name="email"
                value={formData.email}
                className="w-full bg-dark/50 border border-primary/10 text-secondary/70 rounded-lg px-4 py-3 cursor-not-allowed"
                disabled
                readOnly
                title="Email cannot be changed"
              />
            </div>

            <div className="space-y-2">
              <label className="text-secondary flex items-center gap-2 text-sm font-medium">
                <Phone className="w-4 h-4 text-primary" />
                Phone Number
              </label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="+1 (555) 000-0000"
                className="w-full bg-dark border border-primary/30 text-light rounded-lg px-4 py-3 focus:outline-none focus:border-primary transition-colors"
              />
            </div>

            <div className="space-y-2">
              <label className="text-secondary flex items-center gap-2 text-sm font-medium">
                <MapPin className="w-4 h-4 text-primary" />
                Billing Address
              </label>
              <input
                type="text"
                name="address"
                value={formData.address}
                onChange={handleChange}
                placeholder="123 Luxury Ave, City, Country"
                className="w-full bg-dark border border-primary/30 text-light rounded-lg px-4 py-3 focus:outline-none focus:border-primary transition-colors"
              />
            </div>
          </div>

          <div className="pt-4 border-t border-primary/20 flex justify-end">
            <button
              type="submit"
              disabled={loading}
              className="bg-primary hover:bg-primary/90 text-dark font-medium py-3 px-8 rounded-lg transition-all duration-300 disabled:opacity-70 flex justify-center items-center gap-2"
            >
              {loading ? (
                <>
                  <span className="animate-spin h-4 w-4 border-2 border-dark border-t-transparent rounded-full"></span>
                  Saving...
                </>
              ) : (
                "Save Changes"
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};
